<pre>
#include <iostream>
using namespace std;

class Student {
public:
    string name;
    int score;

    void input() {
        cout << "Enter student name: ";
        cin >> name;
        cout << "Enter score: ";
        cin >> score;
    }

    void display() {
        cout << "Name: " << name << endl;
        cout << "Score: " << score << endl;

        if (score >= 50) {
            cout << "Result: Pass" << endl;
        } else {
            cout << "Result: Fail" << endl;
        }
    }
};

int main() {
    Student s1;
    s1.input();
    cout << endl;
    s1.display();

    return 0;
}
</pre>

