<h1>C# Variables & Data Types</h1>

<h3>бһҮбҹҶбһ бһ¶бһ“бһ‘бһёбҹЎ: бһҹбҹ’бһӮбһ¶бһӣбҹӢ Variables</h3>
<p>Variable бһӮбһәбһҮбһ¶бһҖбһ“бҹ’бһӣбҹӮбһ„бһҹбһҳбҹ’бһҡбһ¶бһ”бҹӢбһҡбһҖбҹ’бһҹбһ¶бһ‘бһ»бһҖбһ‘бһ·бһ“бҹ’бһ“бһ“бҹҗбһҷбһҖбҹ’бһ“бһ»бһ„бһҖбһҳбҹ’бһҳбһңбһ·бһ’бһёбҹ” бһҖбҹ’бһ“бһ»бһ„ C# бһҷбһҫбһ„бһҸбҹ’бһҡбһјбһңбһҖбҹҶбһҺбһҸбҹӢбһ”бҹ’бһҡбһ—бҹҒбһ‘бһ‘бһ·бһ“бҹ’бһ“бһ“бҹҗбһҷ (Data Type) бһҳбһ»бһ“бһ–бҹҒбһӣбһ”бҹ’бһҡбһҫ variableбҹ”</p>

<h3>бһҮбҹҶбһ бһ¶бһ“бһ‘бһёбҹў: Example Variables</h3>
<pre>
using System;

class Program
{
    static void Main()
    {
        int age = 20;
        string name = "Dara";

        Console.WriteLine(name);
        Console.WriteLine(age);
    }
}
</pre>

<h3>бһҮбҹҶбһ бһ¶бһ“бһ‘бһёбҹЈ: Data Types бһҹбҹҶбһҒбһ¶бһ“бҹӢбҹ—</h3>
<ul>
<li><b>int</b> : бһҹбһҳбҹ’бһҡбһ¶бһ”бҹӢбһӣбҹҒбһҒбһӮбһҸбҹӢ</li>
<li><b>double</b> : бһҹбһҳбҹ’бһҡбһ¶бһ”бҹӢбһӣбҹҒбһҒбһ‘бһҹбһ—бһ¶бһӮ</li>
<li><b>string</b> : бһҹбһҳбҹ’бһҡбһ¶бһ”бҹӢ text</li>
<li><b>char</b> : бһҹбһҳбҹ’бһҡбһ¶бһ”бҹӢбһўбһҖбҹ’бһҹбһҡбһҸбҹӮбһҳбһҪбһҷ</li>
<li><b>bool</b> : true бһ¬ false</li>
</ul>

<h3>бһҮбҹҶбһ бһ¶бһ“бһ‘бһёбҹӨ: Example Data Types</h3>
<pre>
using System;

class Program
{
    static void Main()
    {
        int age = 21;
        double score = 8.5;
        string name = "Sok";
        char grade = 'A';
        bool isStudent = true;

        Console.WriteLine(age);
        Console.WriteLine(score);
        Console.WriteLine(name);
        Console.WriteLine(grade);
        Console.WriteLine(isStudent);
    }
}
</pre>

<h3>бһҮбҹҶбһ бһ¶бһ“бһ‘бһёбҹҘ: Practice</h3>
<p>бһҹбһ¶бһҖбһӣбҹ’бһ”бһ„бһҹбһҡбһҹбҹҒбһҡ C# program бһҠбҹӮбһӣ:</p>
<ul>
<li>бһ”бһ„бҹ’бһҖбһҫбһҸ variable <b>name</b> (string)</li>
<li>бһ”бһ„бҹ’бһҖбһҫбһҸ variable <b>age</b> (int)</li>
<li>бһ”бһ„бҹ’бһҖбһҫбһҸ variable <b>height</b> (double)</li>
<li>бһ”бһ„бҹ’бһ бһ¶бһү values бһ‘бһ¶бҹҶбһ„бһўбһҹбҹӢбһҠбҹ„бһҷбһ”бҹ’бһҡбһҫ <b>Console.WriteLine()</b></li>
</ul>

<p>бһҹбһҡбһҹбҹҒбһҡбһҖбһјбһҠбһҡбһ”бһҹбҹӢбһўбҹ’бһ“бһҖбһ“бҹ…бһҖбҹ’бһ“бһ»бһ„ editor бһҒбһ¶бһ„бһҖбҹ’бһҡбҹ„бһҳ рҹ‘Ү</p>

бһ”бҹ’бһҡбһҸбһ·бһ”бһҸбҹ’бһҸбһ·бһҖбһ¶бһҡ бһ“бһ·бһ„бһҖбһ¶бһҡбһӮбһҺбһ“бһ¶ бһҖбҹ’бһ“бһ»бһ„ C#
<h1>C# Operators & Calculations</h1>

<h3>бһҮбҹҶбһ бһ¶бһ“бһ‘бһёбҹЎ: бһҹбҹ’бһӮбһ¶бһӣбҹӢ Operators</h3>
<p>Operators бһӮбһәбһҮбһ¶бһҹбһүбҹ’бһүбһ¶бһҠбҹӮбһӣбһ”бҹ’бһҡбһҫбһҹбһҳбҹ’бһҡбһ¶бһ”бҹӢбһ’бҹ’бһңбһҫбһ”бҹ’бһҡбһҸбһ·бһ”бһҸбҹ’бһҸбһ·бһҖбһ¶бһҡбһӣбһҫ variables бһ¬ values бһҠбһјбһ…бһҮбһ¶ бһ”бһјбһҖ бһҠбһҖ бһӮбһ»бһҺ бһ“бһ·бһ„бһ…бҹӮбһҖбҹ”</p>

<h3>бһҮбҹҶбһ бһ¶бһ“бһ‘бһёбҹў: Arithmetic Operators</h3>
<ul>
<li><b>+</b> бһ”бһјбһҖ</li>
<li><b>-</b> бһҠбһҖ</li>
<li><b>*</b> бһӮбһ»бһҺ</li>
<li><b>/</b> бһ…бҹӮбһҖ</li>
<li><b>%</b> бһҹбҹҶбһҺбһӣбҹӢ (modulus)</li>
</ul>

<h3>бһҮбҹҶбһ бһ¶бһ“бһ‘бһёбҹЈ: Example Calculation</h3>
<pre>
using System;

class Program
{
    static void Main()
    {
        int a = 10;
        int b = 3;

        Console.WriteLine(a + b);
        Console.WriteLine(a - b);
        Console.WriteLine(a * b);
        Console.WriteLine(a / b);
        Console.WriteLine(a % b);
    }
}
</pre>

<h3>бһҮбҹҶбһ бһ¶бһ“бһ‘бһёбҹӨ: Increment бһ“бһ·бһ„ Decrement</h3>
<pre>
int x = 5;
x++;
Console.WriteLine(x);

x--;
Console.WriteLine(x);
</pre>

<p><b>++</b> бһ”бһ„бҹ’бһҖбһҫбһ“бһҸбһҳбҹ’бһӣбҹғ 1 бһ“бһ·бһ„ <b>--</b> бһ”бһ“бҹ’бһҗбһҷбһҸбһҳбҹ’бһӣбҹғ 1бҹ”</p>

<h3>бһҮбҹҶбһ бһ¶бһ“бһ‘бһёбҹҘ: Assignment Operators</h3>
<pre>
int num = 10;
num += 5;
Console.WriteLine(num);
</pre>

<p>бһҖбһјбһҠбһ“бҹҒбҹҮбһҳбһ¶бһ“бһ“бҹҗбһҷбһҗбһ¶ num = num + 5бҹ”</p>

<h3>бһҮбҹҶбһ бһ¶бһ“бһ‘бһёбҹҰ: Practice</h3>
<p>бһҹбһ¶бһҖбһӣбҹ’бһ”бһ„бһҹбһҡбһҹбҹҒбһҡ C# program бһҠбҹӮбһӣ:</p>
<ul>
<li>бһ”бһ„бҹ’бһҖбһҫбһҸ variables a = 15 бһ“бһ·бһ„ b = 4</li>
<li>бһ”бһ„бҹ’бһ бһ¶бһүбһӣбһ‘бҹ’бһ’бһ•бһӣ a + b</li>
<li>бһ”бһ„бҹ’бһ бһ¶бһүбһӣбһ‘бҹ’бһ’бһ•бһӣ a * b</li>
<li>бһ”бһ„бҹ’бһ бһ¶бһүбһӣбһ‘бҹ’бһ’бһ•бһӣ a % b</li>
</ul>

<p>бһҹбһҡбһҹбҹҒбһҡбһҖбһјбһҠбһҡбһ”бһҹбҹӢбһўбҹ’бһ“бһҖбһ“бҹ…бһҖбҹ’бһ“бһ»бһ„ editor бһҒбһ¶бһ„бһҖбҹ’бһҡбҹ„бһҳ рҹ‘Ү</p>

бһӣбһҖбҹ’бһҒбһҒбһҺбҹ’бһҢ if бһ“бһ·бһ„ switch бһҖбҹ’бһ“бһ»бһ„ C#
<h1>C# Conditional Statements</h1>

<h3>бһҮбҹҶбһ бһ¶бһ“бһ‘бһёбҹЎ: бһҹбҹ’бһӮбһ¶бһӣбҹӢ Conditional Statements</h3>
<p>Conditional Statements бһ”бҹ’бһҡбһҫбһҹбһҳбҹ’бһҡбһ¶бһ”бҹӢбһ’бҹ’бһңбһҫбһҖбһ¶бһҡбһҹбһҳбҹ’бһҡбҹҒбһ…бһ…бһ·бһҸбҹ’бһҸбһҖбҹ’бһ“бһ»бһ„бһҖбһҳбҹ’бһҳбһңбһ·бһ’бһёбҹ” бһҖбһјбһҠбһ“бһ№бһ„бһҠбҹҶбһҺбһҫбһҡбһҖбһ¶бһҡбһ•бҹ’бһҹбҹҒбһ„бһӮбҹ’бһ“бһ¶ бһўбһ¶бһҹбҹ’бһҡбҹҗбһҷбһӣбһҫбһӣбһҖбҹ’бһҒбһҒбһҺбҹ’бһҢбһҠбҹӮбһӣбһ”бһ¶бһ“бһҖбҹҶбһҺбһҸбҹӢбҹ”</p>

<h3>бһҮбҹҶбһ бһ¶бһ“бһ‘бһёбҹў: if Statement</h3>
<pre>
using System;

class Program
{
    static void Main()
    {
        int age = 18;

        if (age >= 18)
        {
            Console.WriteLine("You are an adult");
        }
    }
}
</pre>

<h3>бһҮбҹҶбһ бһ¶бһ“бһ‘бһёбҹЈ: if...else</h3>
<pre>
using System;

class Program
{
    static void Main()
    {
        int number = 7;

        if (number % 2 == 0)
        {
            Console.WriteLine("Even number");
        }
        else
        {
            Console.WriteLine("Odd number");
        }
    }
}
</pre>

<h3>бһҮбҹҶбһ бһ¶бһ“бһ‘бһёбҹӨ: switch Statement</h3>
<pre>
using System;

class Program
{
    static void Main()
    {
        int day = 2;

        switch (day)
        {
            case 1:
                Console.WriteLine("Monday");
                break;
            case 2:
                Console.WriteLine("Tuesday");
                break;
            case 3:
                Console.WriteLine("Wednesday");
                break;
            default:
                Console.WriteLine("Other day");
                break;
        }
    }
}
</pre>

<h3>бһҮбҹҶбһ бһ¶бһ“бһ‘бһёбҹҘ: Practice</h3>
<p>бһҹбһ¶бһҖбһӣбҹ’бһ”бһ„бһҹбһҡбһҹбҹҒбһҡ C# program бһҠбҹӮбһӣ:</p>
<ul>
<li>бһ”бһ„бҹ’бһҖбһҫбһҸ variable <b>score</b></li>
<li>бһ”бҹ’бһҡбһҹбһ·бһ“бһ”бһҫ score >= 50 бһ”бһ„бҹ’бһ бһ¶бһү "Pass"</li>
<li>бһ”бһҫ score < 50 бһ”бһ„бҹ’бһ бһ¶бһү "Fail"</li>
</ul>

<p>бһҹбһҡбһҹбҹҒбһҡбһҖбһјбһҠбһҡбһ”бһҹбҹӢбһўбҹ’бһ“бһҖбһ“бҹ…бһҖбҹ’бһ“бһ»бһ„ editor бһҒбһ¶бһ„бһҖбҹ’бһҡбҹ„бһҳ рҹ‘Ү</p>

Loop бһ“бһ·бһ„ Iteration бһҖбҹ’бһ“бһ»бһ„ C#
<h1>C# Loops & Iteration</h1>

<h3>бһҮбҹҶбһ бһ¶бһ“бһ‘бһёбҹЎ: бһҹбҹ’бһӮбһ¶бһӣбҹӢ Loop</h3>
<p>Loop бһӮбһәбһҮбһ¶бһҖбһ¶бһҡбһ”бһүбҹ’бһҮбһ¶бһұбҹ’бһҷбһҖбһҳбҹ’бһҳбһңбһ·бһ’бһёбһ’бҹ’бһңбһҫбһҖбһ¶бһҡбһ„бһ¶бһҡбһҠбһҠбҹӮбһӣбҹ—бһҳбҹ’бһҸбһ„бһ бһҫбһҷбһҳбҹ’бһҸбһ„бһ‘бҹҖбһҸ бһҡбһ бһјбһҸбһҠбһӣбҹӢбһӣбһҖбҹ’бһҒбһҒбһҺбҹ’бһҢбһҳбһҪбһҷбһҸбҹ’бһҡбһјбһңбһ”бһ¶бһ“бһ”бҹҶбһ–бҹҒбһүбҹ” C# бһҳбһ¶бһ“ loops бһҹбҹҶбһҒбһ¶бһ“бҹӢбҹ—бһҠбһјбһ…бһҮбһ¶ <b>for</b>, <b>while</b> бһ“бһ·бһ„ <b>do-while</b>бҹ”</p>

<h3>бһҮбҹҶбһ бһ¶бһ“бһ‘бһёбҹў: for Loop</h3>
<pre>
using System;

class Program
{
    static void Main()
    {
        for (int i = 1; i <= 5; i++)
        {
            Console.WriteLine(i);
        }
    }
}
</pre>

<p>бһҖбһјбһҠбһ“бҹҒбҹҮбһ“бһ№бһ„бһ”бһ„бҹ’бһ бһ¶бһүбһӣбҹҒбһҒбһ–бһё 1 бһҠбһӣбҹӢ 5бҹ”</p>

<h3>бһҮбҹҶбһ бһ¶бһ“бһ‘бһёбҹЈ: while Loop</h3>
<pre>
using System;

class Program
{
    static void Main()
    {
        int i = 1;

        while (i <= 5)
        {
            Console.WriteLine(i);
            i++;
        }
    }
}
</pre>

<h3>бһҮбҹҶбһ бһ¶бһ“бһ‘бһёбҹӨ: do...while Loop</h3>
<pre>
using System;

class Program
{
    static void Main()
    {
        int i = 1;

        do
        {
            Console.WriteLine(i);
            i++;
        } while (i <= 5);
    }
}
</pre>

<h3>бһҮбҹҶбһ бһ¶бһ“бһ‘бһёбҹҘ: break бһ“бһ·бһ„ continue</h3>
<pre>
for (int i = 1; i <= 5; i++)
{
    if (i == 3)
    {
        continue;
    }

    Console.WriteLine(i);
}
</pre>

<p><b>continue</b> бһ“бһ№бһ„бһҡбҹҶбһӣбһ„ iteration бһҳбһҪбһҷбһҖбҹ’бһ“бһ»бһ„ loopбҹ”</p>

<h3>бһҮбҹҶбһ бһ¶бһ“бһ‘бһёбҹҰ: Practice</h3>
<p>бһҹбһ¶бһҖбһӣбҹ’бһ”бһ„бһҹбһҡбһҹбҹҒбһҡ C# program бһҠбҹӮбһӣ:</p>
<ul>
<li>бһ”бҹ’бһҡбһҫ for loop бһ”бһ„бҹ’бһ бһ¶бһүбһӣбҹҒбһҒбһ–бһё 1 бһҠбһӣбҹӢ 10</li>
<li>бһ”бҹ’бһҡбһҫ while loop бһ”бһ„бҹ’бһ бһ¶бһүбһӣбҹҒбһҒбһ–бһё 10 бһҠбһӣбҹӢ 1</li>
</ul>

<p>бһҹбһҡбһҹбҹҒбһҡбһҖбһјбһҠбһҡбһ”бһҹбҹӢбһўбҹ’бһ“бһҖбһ“бҹ…бһҖбҹ’бһ“бһ»бһ„ editor бһҒбһ¶бһ„бһҖбҹ’бһҡбҹ„бһҳ рҹ‘Ү</p>

Array бһ“бһ·бһ„ List бһҳбһјбһӣбһҠбҹ’бһӢбһ¶бһ“ бһҖбҹ’бһ“бһ»бһ„ C#
<h1>C# Arrays & Lists Basics</h1>

<h3>бһҮбҹҶбһ бһ¶бһ“бһ‘бһёбҹЎ: бһҹбҹ’бһӮбһ¶бһӣбҹӢ Array</h3>
<p>Array бһӮбһәбһҮбһ¶бһҖбһ¶бһҡбһ”бҹ’бһҡбһҳбһјбһӣбһ‘бһ·бһ“бҹ’бһ“бһ“бҹҗбһҷбһҮбһ¶бһ…бҹ’бһҡбһҫбһ“бһҠбҹӮбһӣбһҳбһ¶бһ“бһ”бҹ’бһҡбһ—бҹҒбһ‘бһҠбһјбһ…бһӮбҹ’бһ“бһ¶ бһ бһҫбһҷбһҡбһҖбҹ’бһҹбһ¶бһ‘бһ»бһҖбһҖбҹ’бһ“бһ»бһ„ variable бһҳбһҪбһҷбҹ”</p>

<h3>бһҮбҹҶбһ бһ¶бһ“бһ‘бһёбҹў: Example Array</h3>
<pre>
using System;

class Program
{
    static void Main()
    {
        int[] numbers = {1, 2, 3, 4, 5};

        Console.WriteLine(numbers[0]);
        Console.WriteLine(numbers[1]);
    }
}
</pre>

<p>Array index бһ…бһ¶бһ”бҹӢбһ•бҹ’бһҸбһҫбһҳбһ–бһё 0бҹ”</p>

<h3>бһҮбҹҶбһ бһ¶бһ“бһ‘бһёбҹЈ: Loop бһҮбһ¶бһҳбһҪбһҷ Array</h3>
<pre>
int[] numbers = {10, 20, 30, 40};

for (int i = 0; i < numbers.Length; i++)
{
    Console.WriteLine(numbers[i]);
}
</pre>

<h3>бһҮбҹҶбһ бһ¶бһ“бһ‘бһёбҹӨ: бһҹбҹ’бһӮбһ¶бһӣбҹӢ List</h3>
<p>List бһӮбһәбһҮбһ¶бһ”бҹ’бһҡбһ—бҹҒбһ‘ collection бһҠбҹӮбһӣбһўбһ¶бһ…бһ”бһ“бҹ’бһҗбҹӮбһҳ бһ¬бһӣбһ»бһ”бһ‘бһ·бһ“бҹ’бһ“бһ“бҹҗбһҷбһ”бһ¶бһ“бһҷбҹүбһ¶бһ„бһ„бһ¶бһҷбһҹбҹ’бһҡбһҪбһӣбҹ”</p>

<pre>
using System;
using System.Collections.Generic;

class Program
{
    static void Main()
    {
        List<string> fruits = new List<string>();

        fruits.Add("Apple");
